using System;

class Program
{
    static void Main(string[] args)
    {
        int age = 25;
        string name = "Murad";
        double height = 1.75;
        bool isStudent = true;
        char initial = 'M';

        Console.WriteLine($"Ad: {name}");
        Console.WriteLine($"Yaş: {age}");
        Console.WriteLine($"Boy: {height} m");
        Console.WriteLine($"Tələbədir: {isStudent}");
        Console.WriteLine($"İlk hərf: {initial}");
    }
}
// Output:
// Ad: Murad
// Yaş: 25
// Boy: 1.75 m
// Tələbədir: True
// İlk hərf: M

